VALUES
  ('elementary-f29af906-moex-00208', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依據公務人員行政中立法，公務人員從事下列何種行為必然違反行政中立之規範？', '["公開為作為議員候選人之配偶拉票", "參與直轄市市長候選人之造勢活動", "發起反統或反獨之政黨集會遊行", "參與連署政務官發起之公投提案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00209', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '為揚棄過往官方統治的觀念並彰顯地方特色，藉以提高政府效率，近年來政府施政強調「地方治理」的理 念。下列何者符合「地方治理」的精神？', '["新冠肺炎疫情期間，疫調、匡列與確診者足跡公布委由地方政府執行", "烏俄戰火蔓延之際，國內民眾募資援助烏克蘭，企業也跟進抵制俄國", "因應人口老化，衛生福利部與地方政府、民間單位推動一學區一日照中心", "地方政府採購新冠肺炎疫苗後交由中央疫情指揮中心統一調配"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00210', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '俄羅斯攻打烏克蘭之後，引發俄國國內的反戰聲浪，但總統普丁（VladimirPutin）一方面逮捕這些抗議人 士，另一方面透過立法宣布所有獨立報導都是犯罪行為。除關閉國內兩家獨立媒體外，諸多外國媒體也陸 續被迫停播或暫停在俄羅斯的採訪工作。若從民主國家統治正當性的角度檢視，前述報導凸顯俄羅斯的統 治缺乏何種正當性？', '["是否允許不同政黨的設立", "國家領導人是否定期改選", "是否保障公平開放的媒體", "總統是否由人民直接選出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00211', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '德國為內閣制國家，2021年國會大選結果，席次率最高的三個政黨依序為：社民黨約占25.7%，基民盟約 占24.1%，綠黨約占14.8%；最後由社民黨的蕭茲（OlafScholz）擔任總理一職。依據德國的政府體制判 斷，下列分析何者正確？', '["社民黨可主導與其他政黨籌組聯合內閣或執政聯盟", "執政黨所提的法案若未通過，可移請國會進行覆議", "蕭茲擔任國家元首職務，屬不具政治實權的精神領袖", "行政機關不須對立法機關負責，落實分權制衡的原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00212', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '甲選區舉行立法委員罷免案投票，該區選舉人總數為235,024人，依選舉委員會統計，投票率為41.93%， 同意票54,813張、不同意票43,340張。依公職人員選舉罷免法規定，此罷免案通過與否的主要理由為何？', '["罷免案通過，因同意罷免的票數多於不同意罷免的票數", "罷免案通過，因罷免案之投票率達選舉人總數四分之一", "罷免案不通過，因罷免案之投票率未達選舉人總數二分之一", "罷免案不通過，因同意票未達選舉人總數四分之一以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00213', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '關於利益團體與政黨的比較，下列敘述何者正確？', '["利益團體關注的政策面向較政黨更全面", "利益團體及政黨均為人民參政權的展現", "利益團體與政黨皆受人民團體法規範", "利益團體與政黨可透過倡議方式影響政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00214', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依據公民投票法之規定，下列敘述何者正確？', '["公民投票涉及原住民族權利者，不得違反原住民族基本法之規定", "公民投票僅限於全國性公民投票，地方自治團體不得舉辦地方性公民投票", "立法院基於責任政治之要求，不得提案舉辦公民投票", "經複決廢止之法律，立法機關仍得於1年後再制定相同之法律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00215', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依據公職人員選舉罷免法之規定，下列何者具有候選人登記資格？', '["現於區公所服替代役之役男", "私立大學碩士班之在籍學生", "曾犯貪污罪而受緩刑宣告者", "受破產宣告確定而尚未復權者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00216', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依據臺灣地區與大陸地區人民關係條例之規定，若大陸地區人民未經許可進入臺灣地區，由下列何機關執 行強制出境作業？', '["內政部移民署", "內政部警政署", "行政院大陸委員會", "海洋委員會海巡署"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00217', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '民主國家對於政府應擔負服務人民的角色有不同的期許，下列何者是最基本的民主價值，也是有限政府應 從事的作為？', '["充分保障私有財產權", "有免費疫苗可以施打", "就讀高等教育免學費", "控制物價與通貨膨脹"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
